1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const LOYALTY_RATE = 0.2;
8	const FOLLOW_UP_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
