28	const groupCountsByType = (items: Item[]): Map<string, number> => {
29	  const counts = new Map<string, number>();
30	  for (const { type } of items) {
31	    counts.set(type, (counts.get(type) ?? 0) + 1);
32	  }
33	  return counts;
34	};
35	
36	const basePremiumForGroup = (type: string, count: number): number => {
37	  if (!(type in BASE_PREMIUM)) {
38	    throw new Error(`unknown item type: ${type}`);
39	  }
40	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
41	  return count * BASE_PREMIUM[type];
42	};
43	
44	const basePremiumFor = (items: Item[]): number =>
45	  Array.from(groupCountsByType(items)).reduce(
46	    (total, [type, count]) => total + basePremiumForGroup(type, count),
47	    0,
48	  );
49	
50	const curseSurchargeFor = (item: Item): number =>
51	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
52	
53	const highEnchantmentSurchargeFor = (item: Item): number =>
54	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
55	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
56	    : 0;
57	
58	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
59	  curseSurchargeFor,
60	  highEnchantmentSurchargeFor,
61	];
62	
63	const surchargesForItem = (item: Item): number =>
64	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
65	
66	const itemSurchargesFor = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
68	
69	const firstInsuranceSurchargeFor = (basePremium: number): number =>
70	  basePremium * FIRST_INSURANCE_RATE;
71	
72	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
73	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
74	    ? basePremium * LOYALTY_RATE
75	    : 0;
76	
77	const followUpDiscountFor = (basePremium: number, isFollowUp: boolean): number =>
78	  isFollowUp ? basePremium * FOLLOW_UP_RATE : 0;
79	
80	const premiumFor = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
81	  const basePremium = basePremiumFor(items);
82	  return Math.ceil(
83	    basePremium +
84	      itemSurchargesFor(items) +
85	      firstInsuranceSurchargeFor(basePremium) -
86	      loyaltyDiscountFor(basePremium, customer) -
87	      followUpDiscountFor(basePremium, isFollowUp) +
88	      PROCESSING_FEE,
89	  );
90	};
91	
92	const quoteStep = (
93	  { items }: Step,
94	  customer: Customer,
95	  isFollowUp: boolean,
96	): QuoteResult => ({
97	  premium: premiumFor(items, customer, isFollowUp),
98	});
99	
100	export const runScenario = (input: Scenario): ScenarioOutput => ({
101	  results: input.steps.map((step, i) => quoteStep(step, input.customer, i > 0)),
102	});
